UPDATE practice_finding SET verdict = 'NOT_OBSERVED' WHERE verdict = 'NEGATIVE';
ALTER TABLE practice_finding ADD CONSTRAINT chk_practice_finding_verdict
    CHECK (verdict IN ('OBSERVED', 'NOT_OBSERVED', 'NOT_APPLICABLE'));

