changeSet.sql:
UPDATE finding_reaction fr SET correlation_key = pf.correlation_key
FROM practice_finding pf
WHERE fr.finding_id = pf.id AND pf.correlation_key IS NOT NULL AND fr.correlation_key IS NULL;

UPDATE feedback SET suppression_reason = 'REVIEWER_SIDE' WHERE suppression_reason = 'AUDIENCE_REVIEWER';
ALTER TABLE feedback DROP CONSTRAINT IF EXISTS chk_feedback_suppression_reason;
ALTER TABLE feedback ADD CONSTRAINT chk_feedback_suppression_reason CHECK (suppression_reason IS NULL OR suppression_reason IN ('REVIEWER_SIDE', 'BELOW_THRESHOLD', 'LOW_CONFIDENCE', 'POLICY_FLOOR_DROP', 'REACTED_DISPUTED', 'REACTED_NOT_APPLICABLE'));

changeSet.rollback:
